/**
 * premiumContent.ts
 * 
 * Premium educational quiz content for kids ages 3-10.
 * All content is stored as TypeScript constants for offline use.
 * 
 * Contents:
 *   1. Interfaces (PremiumQuestion, AdvancedMathQuestion, VocabularyWord, ScienceQuestion)
 *   2. premiumQuestions       — 400+ general quiz questions
 *   3. advancedMathQuestions  — 150+ advanced math questions
 *   4. vocabularyWords        — 200+ vocabulary words
 *   5. scienceQuestions       — 200+ science questions
 *   6. dailyChallenges        — 50+ daily challenge questions
 *   7. weeklyChallenges       — 50+ weekly challenge questions
 * 
 * Total: 1000+ questions across all arrays combined.
 */

// ============================================================================
// INTERFACES
// ============================================================================

export interface PremiumQuestion {
  id: number;
  category: string;
  question: string;
  options: string[];
  answer: number; // 0-based index into options
  difficulty: 'easy' | 'medium' | 'hard';
  explanation?: string;
}

export interface AdvancedMathQuestion {
  id: number;
  type: 'multiplication' | 'division' | 'fractions' | 'decimals' | 'percentages' | 'algebra' | 'geometry';
  question: string;
  options: number[];
  answer: number;
  difficulty: 'medium' | 'hard';
  explanation?: string;
}

export interface VocabularyWord {
  id: number;
  word: string;
  meaning: string;
  example: string;
  synonyms: string[];
  antonyms: string[];
  level: 'beginner' | 'intermediate' | 'advanced';
}

export interface ScienceQuestion {
  id: number;
  topic: 'physics' | 'chemistry' | 'biology' | 'earth' | 'space' | 'general';
  question: string;
  options: string[];
  answer: number;
  difficulty: 'easy' | 'medium' | 'hard';
  explanation?: string;
}

